// Get .tex file paths from the first input (Filter .tex Files)
const texFiles = $('Filter .tex Files').all().map(item => item.json.path);

// Get all uploaded PDF filenames from Supabase
const uploadedPdfs = $('Get All Uploaded PDFs').all().map(item => item.json.original_filename);

// For each .tex file, check if its corresponding .pdf has been uploaded
// The PDF filename is the basename of the path with .tex replaced by .pdf
const missingFiles = [];

for (const texPath of texFiles) {
  // Convert path: "semester2/AI/lecture1.tex" -> "lecture1.pdf"
  const pdfFilename = texPath.split('/').pop().replace('.tex', '.pdf');

  // Check if this PDF exists in the uploaded PDFs
  const isUploaded = uploadedPdfs.some(uploaded => uploaded === pdfFilename);

  if (!isUploaded) {
    missingFiles.push({ json: { filenames: texPath } });
  }
}

if (missingFiles.length === 0) {
  return [{ json: { filenames: '__NONE__', empty: true } }];
}

return missingFiles;

