function extractJson(text) {
  if (typeof text !== 'string') return null;

  const fenced = text.match(/(?:```|''')\w*\s*([\s\S]*?)(?:```|''')/);
  const candidate = fenced ? fenced[1] : text;

  const jsonMatch = candidate.match(/[\[{][\s\S]*[\]}]/);
  if (!jsonMatch) return null;

  try {
    return JSON.parse(jsonMatch[0]);
  } catch (e) {
    return null;
  }
}

for (const item of items) {
  item.json.extracted_code = extractJson(item.json.output);
}
return items;

try {
    let flashcards = $('Loop Over Items2').item.json.extracted_code;

    if (typeof flashcards === 'string') {
        flashcards = JSON.parse(flashcards);
    }

    if (!Array.isArray(flashcards) || flashcards.length === 0) {
        return [{ json: { error: "No valid flashcards found" } }];
    }

    const moduleSet = new Set();
    const topicSet = new Set();
    const subtopicSet = new Set();
    const tagSet = new Set();

    flashcards.forEach(card => {
        const module = card.Module || card.module;
        const topic = card.Topic || card.topic;
        const subtopic = card["Sub-Topic"] || card["Sub Topic"] || card.subtopic || card.Subtopic;
        const tags = card.Tags || card.tags;

        if (module && typeof module === 'string') {
            moduleSet.add(module.trim());
        }

        if (topic && typeof topic === 'string') {
            topicSet.add(topic.trim());
        }

        if (subtopic && typeof subtopic === 'string') {
            subtopicSet.add(subtopic.trim());
        }

        if (tags && Array.isArray(tags)) {
            tags.forEach(tag => {
                if (tag && typeof tag === 'string') {
                    tagSet.add(tag.trim().toLowerCase());
                }
            });
        }
    });

    return [{
        json: {
            module_name: Array.from(moduleSet)[0] || "",
            topic_names: Array.from(topicSet).join(','),
            subtopic_names: Array.from(subtopicSet).join(','),
            tag_names: Array.from(tagSet).join(',')
        }
    }];

} catch (error) {
    return [{ json: { error: `Failed: ${error.message}` } }];
}

